public int nextIndexOf(CharSequence seq){
        char startChar = seq.charAt(0);
        boolean flag = false;
        int index=pos;
         while (index<input.length&&(!flag)){
             if (startChar==input[index]){
                 if (seq.toString().equals((new String(Arrays.copyOfRange(input,index,Math.min(index+seq.length(),input.length)))).trim())){
                     flag = true;

                 }
             }
             index++;

         }
         if (!flag){
             return -1;
         } else{
             return index-pos;
         }
     }

